      y: Math.max(0.1, (sourceBoundingBox.maximum.y - sourceBoundingBox.minimum.y) * 0.5),
      z: Math.max(0.1, (sourceBoundingBox.maximum.z - sourceBoundingBox.minimum.z) * 0.5),
