              boxA.position.y += sign * correction;
              boxB.position.y -= sign * correction;
            } else {
              const sign = boxA.position.z < boxB.position.z ? -1 : 1;
              boxA.position.z += sign * correction;
              boxB.position.z -= sign * correction;
            }
            movedAny = true;
          }
