  }

  private getCrossFilePairKey(fileA: string, fileB: string): string {
    const a = toProjectRelativePath(fileA);
    const b = toProjectRelativePath(fileB);
    return a.localeCompare(b) <= 0 ? `${a}<->${b}` : `${b}<->${a}`;
