    }
    return new BABYLON.Vector3(0, 0, fallbackNormal.z >= 0 ? 1 : -1);
  }

  /**
   * Compare two face normals with floating-point tolerance
   */
  public isFaceNormalEqual(a: BABYLON.Vector3 | null, b: BABYLON.Vector3 | null): boolean {
    if (!a || !b) return false;
    const tolerance = 0.1;
